import{_ as a,o as e,c as s,aw as n}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"Celestia","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Celestia | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/da-layers/celestia.md","filePath":"guides/da-layers/celestia.md","lastUpdated":1773819008000}');const t=a({name:"guides/da-layers/celestia.md"},[["render",function(a,o,t,l,i,r){return e(),s("div",null,[...o[0]||(o[0]=[n('<h1 id="celestia" tabindex="-1">Celestia <a class="header-anchor" href="#celestia" aria-label="Permalink to &quot;Celestia&quot;">​</a></h1><p>This guide covers connecting your Evolve chain to Celestia for production data availability.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Completed an Evolve quickstart tutorial</li><li>Familiarity with running a Celestia light node</li></ul><h2 id="running-a-celestia-light-node" tabindex="-1">Running a Celestia Light Node <a class="header-anchor" href="#running-a-celestia-light-node" aria-label="Permalink to &quot;Running a Celestia Light Node&quot;">​</a></h2><p>Before starting your Evolve chain, you need a Celestia light node running and synced.</p><p>Follow the <a href="https://docs.celestia.org/how-to-guides/light-node" target="_blank" rel="noreferrer">Celestia light node documentation</a> to install, initialize, and start a light node for your target network (Arabica, Mocha, or Mainnet).</p><h2 id="configuring-evolve-for-celestia" tabindex="-1">Configuring Evolve for Celestia <a class="header-anchor" href="#configuring-evolve-for-celestia" aria-label="Permalink to &quot;Configuring Evolve for Celestia&quot;">​</a></h2><h3 id="required-configuration" tabindex="-1">Required Configuration <a class="header-anchor" href="#required-configuration" aria-label="Permalink to &quot;Required Configuration&quot;">​</a></h3><p>The following flags are required to connect to Celestia:</p><table tabindex="0"><thead><tr><th>Flag</th><th>Description</th></tr></thead><tbody><tr><td><code>--evnode.da.address</code></td><td>Celestia node RPC endpoint</td></tr><tr><td><code>--evnode.da.auth_token</code></td><td>JWT authentication token</td></tr><tr><td><code>--evnode.da.header_namespace</code></td><td>Namespace for block headers</td></tr><tr><td><code>--evnode.da.data_namespace</code></td><td>Namespace for transaction data</td></tr></tbody></table><h3 id="get-da-block-height" tabindex="-1">Get DA Block Height <a class="header-anchor" href="#get-da-block-height" aria-label="Permalink to &quot;Get DA Block Height&quot;">​</a></h3><p>Query the current DA height to set as your starting point:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">DA_BLOCK_HEIGHT</span><span style="color:#767676;">=$(</span><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> header</span><span style="color:#BFF3C2;"> network-head</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> jq</span><span style="color:#FFECB6;"> -r</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">.result.header.height</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#94EEFF;">echo</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">Your DA_BLOCK_HEIGHT is $DA_BLOCK_HEIGHT</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><h3 id="get-authentication-token" tabindex="-1">Get Authentication Token <a class="header-anchor" href="#get-authentication-token" aria-label="Permalink to &quot;Get Authentication Token&quot;">​</a></h3><p>Generate a write token for your light node:</p><p><strong>Arabica:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">AUTH_TOKEN</span><span style="color:#767676;">=$(</span><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> light</span><span style="color:#BFF3C2;"> auth</span><span style="color:#BFF3C2;"> write</span><span style="color:#FFECB6;"> --p2p.network</span><span style="color:#BFF3C2;"> arabica</span><span style="color:#767676;">)</span></span></code></pre></div><p><strong>Mocha:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">AUTH_TOKEN</span><span style="color:#767676;">=$(</span><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> light</span><span style="color:#BFF3C2;"> auth</span><span style="color:#BFF3C2;"> write</span><span style="color:#FFECB6;"> --p2p.network</span><span style="color:#BFF3C2;"> mocha</span><span style="color:#767676;">)</span></span></code></pre></div><p><strong>Mainnet:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">AUTH_TOKEN</span><span style="color:#767676;">=$(</span><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> light</span><span style="color:#BFF3C2;"> auth</span><span style="color:#BFF3C2;"> write</span><span style="color:#767676;">)</span></span></code></pre></div><h3 id="set-namespaces" tabindex="-1">Set Namespaces <a class="header-anchor" href="#set-namespaces" aria-label="Permalink to &quot;Set Namespaces&quot;">​</a></h3><p>Choose unique namespaces for your chain&#39;s headers and data:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">DA_HEADER_NAMESPACE</span><span style="color:#767676;">=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">my_chain_headers</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#DBD7CA;">DA_DATA_NAMESPACE</span><span style="color:#767676;">=</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#BFF3C2;">my_chain_data</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p>The namespace values are automatically encoded by ev-node for Celestia compatibility.</p><p>You can use the same namespace for both headers and data, or separate them for optimized syncing (light clients can sync headers only).</p><h3 id="set-da-address" tabindex="-1">Set DA Address <a class="header-anchor" href="#set-da-address" aria-label="Permalink to &quot;Set DA Address&quot;">​</a></h3><p>Default Celestia light node port is 26658. <strong>Note:</strong> Connection to a celestia-node DA requires a websocket connection:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">DA_ADDRESS</span><span style="color:#767676;">=</span><span style="color:#BFF3C2;">ws://localhost:26658</span></span></code></pre></div><h2 id="running-your-chain" tabindex="-1">Running Your Chain <a class="header-anchor" href="#running-your-chain" aria-label="Permalink to &quot;Running Your Chain&quot;">​</a></h2><p>Start your chain with Celestia configuration:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">evnode</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.auth_token</span><span style="color:#DBD7CA;"> $AUTH_TOKEN </span><span style="color:#FFECB6;">\\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.header_namespace</span><span style="color:#DBD7CA;"> $DA_HEADER_NAMESPACE </span><span style="color:#FFECB6;">\\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.data_namespace</span><span style="color:#DBD7CA;"> $DA_DATA_NAMESPACE </span><span style="color:#FFECB6;">\\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.address</span><span style="color:#DBD7CA;"> $DA_ADDRESS</span></span></code></pre></div><p>For Cosmos SDK chains:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">appd</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.auth_token</span><span style="color:#DBD7CA;"> $AUTH_TOKEN </span><span style="color:#FFECB6;">\\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.header_namespace</span><span style="color:#DBD7CA;"> $DA_HEADER_NAMESPACE </span><span style="color:#FFECB6;">\\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.data_namespace</span><span style="color:#DBD7CA;"> $DA_DATA_NAMESPACE </span><span style="color:#FFECB6;">\\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --evnode.da.address</span><span style="color:#DBD7CA;"> $DA_ADDRESS</span></span></code></pre></div><h2 id="viewing-your-chain-data" tabindex="-1">Viewing Your Chain Data <a class="header-anchor" href="#viewing-your-chain-data" aria-label="Permalink to &quot;Viewing Your Chain Data&quot;">​</a></h2><p>Once running, you can view your chain&#39;s data on Celestia block explorers:</p><ul><li><a href="https://arabica.celenium.io/" target="_blank" rel="noreferrer">Celenium (Arabica)</a></li><li><a href="https://mocha.celenium.io/" target="_blank" rel="noreferrer">Celenium (Mocha)</a></li><li><a href="https://celenium.io/" target="_blank" rel="noreferrer">Celenium (Mainnet)</a></li></ul><p>Search by your namespace or account address to see submitted blobs.</p><h2 id="configuration-options" tabindex="-1">Configuration Options <a class="header-anchor" href="#configuration-options" aria-label="Permalink to &quot;Configuration Options&quot;">​</a></h2><h3 id="gas-price" tabindex="-1">Gas Price <a class="header-anchor" href="#gas-price" aria-label="Permalink to &quot;Gas Price&quot;">​</a></h3><p>By default, ev-node uses automatic gas price detection. Keep the default unless you have an operational reason to override it:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">--evnode.da.gas_price</span><span style="color:#FFECB6;"> 0.01</span></span></code></pre></div><p>Higher gas prices result in faster inclusion during congestion. Omit this flag to use the automatic default.</p><h3 id="block-time" tabindex="-1">Block Time <a class="header-anchor" href="#block-time" aria-label="Permalink to &quot;Block Time&quot;">​</a></h3><p>Set the expected DA block time (affects retry timing):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">--evnode.da.block_time</span><span style="color:#BFF3C2;"> 6s</span></span></code></pre></div><p>Celestia&#39;s block time is approximately 6 seconds.</p><h3 id="multiple-signing-addresses" tabindex="-1">Multiple Signing Addresses <a class="header-anchor" href="#multiple-signing-addresses" aria-label="Permalink to &quot;Multiple Signing Addresses&quot;">​</a></h3><p>For high-throughput chains, use multiple signing addresses to avoid nonce conflicts:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">--evnode.da.signing_addresses</span><span style="color:#BFF3C2;"> celestia1abc...,celestia1def...,celestia1ghi...</span></span></code></pre></div><p>All addresses must be funded and loaded in the Celestia node&#39;s keyring.</p><h2 id="funding-your-account" tabindex="-1">Funding Your Account <a class="header-anchor" href="#funding-your-account" aria-label="Permalink to &quot;Funding Your Account&quot;">​</a></h2><h3 id="testnet-mocha-arabica" tabindex="-1">Testnet (Mocha/Arabica) <a class="header-anchor" href="#testnet-mocha-arabica" aria-label="Permalink to &quot;Testnet (Mocha/Arabica)&quot;">​</a></h3><p>Get testnet TIA from faucets:</p><ul><li><a href="https://faucet.celestia-mocha.com/" target="_blank" rel="noreferrer">Mocha Faucet</a></li><li><a href="https://faucet.celestia-arabica.com/" target="_blank" rel="noreferrer">Arabica Faucet</a></li></ul><h3 id="mainnet" tabindex="-1">Mainnet <a class="header-anchor" href="#mainnet" aria-label="Permalink to &quot;Mainnet&quot;">​</a></h3><p>Purchase TIA and transfer to your Celestia light node address.</p><p>Check your address:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> state</span><span style="color:#BFF3C2;"> account-address</span></span></code></pre></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="out-of-funds" tabindex="-1">Out of Funds <a class="header-anchor" href="#out-of-funds" aria-label="Permalink to &quot;Out of Funds&quot;">​</a></h3><p>If you see <code>Code: 19</code> errors, your account is out of TIA:</p><ol><li>Fund your account</li><li>Increase gas price to unstick pending transactions</li><li>Restart your chain</li></ol><p>See <a href="/guides/operations/troubleshooting">Troubleshooting Guide</a> for details.</p><h3 id="connection-refused" tabindex="-1">Connection Refused <a class="header-anchor" href="#connection-refused" aria-label="Permalink to &quot;Connection Refused&quot;">​</a></h3><p>Verify your Celestia node is running:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">curl</span><span style="color:#BFF3C2;"> http://localhost:26658/header/sync_state</span></span></code></pre></div><h3 id="token-expired" tabindex="-1">Token Expired <a class="header-anchor" href="#token-expired" aria-label="Permalink to &quot;Token Expired&quot;">​</a></h3><p>Regenerate your auth token:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">celestia</span><span style="color:#BFF3C2;"> light</span><span style="color:#BFF3C2;"> auth</span><span style="color:#BFF3C2;"> write</span><span style="color:#FFECB6;"> --p2p.network</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">networ</span><span style="color:#DBD7CA;">k</span><span style="color:#888888;">&gt;</span></span></code></pre></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/guides/da-layers/local-da">Local DA Guide</a> - Development setup</li><li><a href="/guides/operations/troubleshooting">Troubleshooting</a> - Common issues</li><li><a href="/reference/configuration/ev-node-config">Configuration Reference</a> - All DA options</li></ul>',73)])])}]]);export{o as __pageData,t as default};
